import pika
import json
import time
import sys
from datetime import datetime


class RabbitMQPublisher:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        
    def publish_task(self, task_data):
        if not self.channel:
            self.connect()
            
        message = json.dumps({
            'task_id': task_data.get('task_id'),
            'task_type': task_data.get('task_type'),
            'data': task_data.get('data'),
            'timestamp': datetime.now().isoformat()
        })
        
        self.channel.basic_publish(
            exchange='',
            routing_key=self.queue_name,
            body=message,
            properties=pika.BasicProperties(
                delivery_mode=2,
            )
        )
        print(f"[x] Sent task: {task_data.get('task_id')}")
        
    def close(self):
        if self.connection:
            self.connection.close()


class RabbitMQConsumer:
    def __init__(self, host='localhost', port=5672, queue_name='task_queue'):
        self.host = host
        self.port = port
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        self.connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=self.host, port=self.port)
        )
        self.channel = self.connection.channel()
        self.channel.queue_declare(queue=self.queue_name, durable=True)
        self.channel.basic_qos(prefetch_count=1)
        
    def process_task(self, task_data):
        task_id = task_data.get('task_id')
        task_type = task_data.get('task_type')
        data = task_data.get('data')
        
        print(f"[*] Processing task {task_id} of type {task_type}")
        print(f"[*] Task data: {data}")
        
        time.sleep(2)
        
        print(f"[✓] Task {task_id} completed")
        
    def callback(self, ch, method, properties, body):
        try:
            task_data = json.loads(body)
            print(f"[x] Received task: {task_data.get('task_id')}")
            
            self.process_task(task_data)
            
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as e:
            print(f"[!] Error processing task: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
            
    def start_consuming(self):
        if not self.channel:
            self.connect()
            
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.callback
        )
        
        print('[*] Waiting for tasks. To exit press CTRL+C')
        self.channel.start_consuming()
        
    def close(self):
        if self.connection:
            self.connection.close()


def run_publisher():
    publisher = RabbitMQPublisher()
    
    try:
        publisher.connect()
        
        tasks = [
            {
                'task_id': 'task_001',
                'task_type': 'data_processing',
                'data': {'input': 'file1.csv', 'operation': 'transform'}
            },
            {
                'task_id': 'task_002',
                'task_type': 'image_processing',
                'data': {'input': 'image1.jpg', 'operation': 'resize'}
            },
            {
                'task_id': 'task_003',
                'task_type': 'email_sending',
                'data': {'recipient': 'user@example.com', 'subject': 'Hello'}
            },
            {
                'task_id': 'task_004',
                'task_type': 'report_generation',
                'data': {'report_type': 'monthly', 'format': 'pdf'}
            },
            {
                'task_id': 'task_005',
                'task_type': 'backup',
                'data': {'source': '/data', 'destination': '/backup'}
            }
        ]
        
        for task in tasks:
            publisher.publish_task(task)
            time.sleep(0.5)
            
        print("[✓] All tasks published successfully")
        
    except Exception as e:
        print(f"[!] Publisher error: {e}")
    finally:
        publisher.close()


def run_consumer():
    consumer = RabbitMQConsumer()
    
    try:
        consumer.connect()
        consumer.start_consuming()
    except KeyboardInterrupt:
        print('\n[*] Consumer stopped by user')
    except Exception as e:
        print(f"[!] Consumer error: {e}")
    finally:
        consumer.close()


if __name__ == '__main__':
    if len(sys.argv) > 1:
        if sys.argv[1] == 'publish':
            run_publisher()
        elif sys.argv[1] == 'consume':
            run_consumer()
        else:
            print("Usage: python script.py [publish|consume]")
    else:
        print("Choose mode:")
        print("1. Publisher")
        print("2. Consumer")
        choice = input("Enter choice (1 or 2): ")
        
        if choice == '1':
            run_publisher()
        elif choice == '2':
            run_consumer()
        else:
            print("Invalid choice")